function invert(byOkres: Record<string, readonly string[]>): Record<string, string> {
  const out: Record<string, string> = {};
  for (const okres of Object.keys(byOkres)) {
    for (const name of byOkres[okres] ?? []) out[name] = okres;
  }
  return out;
}

/** Katastrální území name -> okres name. 13074 entries; k.ú. names are unique. */
export const KATASTR_OKRES: Record<string, string> = invert(KATASTR_BY_OKRES);

/**
 * Obec name -> okres name. 4756 of 5346 obec names; names spanning
 * multiple okresy are intentionally omitted so the parser fails loudly instead of
 * picking the wrong okres.
 */
export const OBEC_OKRES: Record<string, string> = invert(OBEC_BY_OKRES);

/** All 77 okresy covered (matches DISTRICTS in ./districts.ts). */
export const OKRESY: readonly string[] = Object.keys(KATASTR_BY_OKRES).sort();
